1	// claim-office.ts
2	//
3	// Design choices for the input shape (documented for future tests):
4	// - quote(input) takes an object with `customer` and `items`.
5	//   - customer: { yearsWithMHPCO: number, isFollowUpContract: boolean }
6	//     - yearsWithMHPCO: how long the customer has been with MHPCO (drives loyalty discount).
7	//     - isFollowUpContract: whether this quote is the customer's second/follow-up
8	//       contract in the scenario (drives the 15% follow-up discount).
9	//   - items: an array of items to be insured. Empty array means no items.
10	// - quote returns the premium in G as a number.
11	// - claim is also exported (per the spec import) but not yet implemented.
12	
13	export type Customer = {
14	  yearsWithMHPCO: number;
15	  isFollowUpContract: boolean;
16	};
17	
18	export type Item = {
19	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
20	  cursed?: boolean;
21	  enchantment?: number;
22	};
23	
24	export type QuoteInput = {
25	  customer: Customer;
26	  items: Item[];
27	};
28	
29	// Flat fee added to every quote at the very end (spec: "processing fee of 5 G").
30	// Currently observed in the empty-list test (premium = fee only).
31	const PROCESSING_FEE = 5;
32	
33	// Block-of-3 discount: when items are exactly 3 of the same type,
34	// the policy base premium for that group is a flat 60 G.
35	const BLOCK_SIZE = 3;
36	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
37	
38	// Base premium per item type, in G (before any modifiers or fees).
39	// Keyed by Item["type"] so adding a new item variant is caught at compile time
40	// (the Record will require a corresponding entry).
41	const BASE_PREMIUM_BY_TYPE: Record<Item["type"], number> = {
42	  sword: 100,
43	  amulet: 60,
44	  staff: 80,
45	  potion: 40,
46	  rune: 25,
47	  moonstone: 25,
48	};
49	
50	// Modifier rates expressed as numerator/denominator to avoid floating-point error
51	// for the integer-and-half cases under test (e.g. 100 * 1.1 ≠ 110 in IEEE-754).
52	//
53	// Item-level surcharges (applied to a single item's base premium):
54	const CURSED_SURCHARGE_NUM = 1;
55	const CURSED_SURCHARGE_DEN = 2; // +50%
56	const HIGH_ENCHANTMENT_SURCHARGE_NUM = 3;
57	const HIGH_ENCHANTMENT_SURCHARGE_DEN = 10; // +30%
58	const HIGH_ENCHANTMENT_THRESHOLD = 5;
59	//
60	// Policy-level modifiers (applied to the policy base premium):
61	const FIRST_INSURANCE_NUM = 1;
62	const FIRST_INSURANCE_DEN = 10; // +10%
63	const LOYALTY_DISCOUNT_NUM = 1;
64	const LOYALTY_DISCOUNT_DEN = 5; // -20%
65	const LOYALTY_THRESHOLD_YEARS = 2;
66	const FOLLOW_UP_DISCOUNT_NUM = 15;
67	const FOLLOW_UP_DISCOUNT_DEN = 100; // -15%
68	
69	// Component types eligible for the block-of-3 discount.
70	const COMPONENT_TYPES: ReadonlySet<Item["type"]> = new Set(["rune", "moonstone"]);
71	
72	function isComponent(item: Item): boolean {
73	  return COMPONENT_TYPES.has(item.type);
74	}
75	
76	function itemBaseOnly(item: Item): number {
77	  return BASE_PREMIUM_BY_TYPE[item.type];
78	}
79	
80	function itemSurcharges(item: Item): number {
81	  const base = BASE_PREMIUM_BY_TYPE[item.type];
82	  let surcharge = 0;
83	  if (item.cursed) {
84	    surcharge += (base * CURSED_SURCHARGE_NUM) / CURSED_SURCHARGE_DEN;
85	  }
86	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
87	    surcharge += (base * HIGH_ENCHANTMENT_SURCHARGE_NUM) / HIGH_ENCHANTMENT_SURCHARGE_DEN;
88	  }
89	  return surcharge;
90	}
91	
92	function groupBaseSum(items: Item[]): number {
93	  return items.reduce((sum, item) => sum + itemBaseOnly(item), 0);
94	}
95	
96	function groupByType(items: Item[]): Map<Item["type"], Item[]> {
97	  const groups = new Map<Item["type"], Item[]>();
98	  for (const item of items) {
99	    const group = groups.get(item.type) ?? [];
100	    group.push(item);
101	    groups.set(item.type, group);
102	  }
103	  return groups;
104	}
105	
106	function groupBasePremium(group: Item[]): number {
107	  if (group.length === BLOCK_SIZE && isComponent(group[0])) {
108	    return BLOCK_OF_THREE_BASE_PREMIUM;
109	  }
110	  return groupBaseSum(group);
111	}
112	
113	function policyBasePremium(items: Item[]): number {
114	  const groups = groupByType(items);
115	  return Array.from(groups.values()).reduce(
116	    (total, group) => total + groupBasePremium(group),
117	    0,
118	  );
119	}
120	
121	function totalItemSurcharges(items: Item[]): number {
122	  return items.reduce((sum, item) => sum + itemSurcharges(item), 0);
123	}
124	
125	export function quote(input: QuoteInput): number {
126	  // policyBase = sum of base premiums (with block-of-3 for components)
127	  // itemSurcharges = curse + high enchantment, each on item base only
128	  // firstInsurance = 10% of policyBase
129	  // loyalty = 20% of policyBase if 2+ years
130	  // followUp = 15% of policyBase if follow-up contract
131	  // total = policyBase + itemSurcharges + firstInsurance - loyalty - followUp + 5
132	  const { customer, items } = input;
133	  const policyBase = policyBasePremium(items);
134	  const surcharges = totalItemSurcharges(items);
135	  const firstInsurance = (policyBase * FIRST_INSURANCE_NUM) / FIRST_INSURANCE_DEN;
136	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
137	    ? (policyBase * LOYALTY_DISCOUNT_NUM) / LOYALTY_DISCOUNT_DEN
138	    : 0;
139	  const followUp = customer.isFollowUpContract
140	    ? (policyBase * FOLLOW_UP_DISCOUNT_NUM) / FOLLOW_UP_DISCOUNT_DEN
141	    : 0;
142	  return Math.ceil(policyBase + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
143	}
144	
145	export function claim(_input: unknown): unknown {
146	  return undefined;
147	}
